cli/internal/bead/property_test.go:165:// TestProperty_ClaimStateMachine verifies the claim/unclaim/close state
cli/internal/bead/property_test.go:166:// machine transitions for a wide range of sequences. The key guarded
cli/internal/bead/property_test.go:167:// transition is Claim, which only succeeds from StatusOpen. All other
cli/internal/bead/property_test.go:168:// transitions (Unclaim, Close, reopen via Update) are idempotent and
cli/internal/bead/property_test.go:169:// never return errors regardless of current status.
cli/internal/bead/property_test.go:170:func TestProperty_ClaimStateMachine(t *testing.T) {
cli/internal/bead/property_test.go:171:	t.Parallel()
cli/internal/bead/property_test.go:172:	s := newTestStore(t)
cli/internal/bead/property_test.go:173:
cli/internal/bead/property_test.go:174:	rng := rand.New(rand.NewSource(9999))
cli/internal/bead/property_test.go:175:	b := &Bead{Title: "state-machine-target"}
cli/internal/bead/property_test.go:176:	require.NoError(t, s.Create(testCtx(), b))
cli/internal/bead/property_test.go:177:	id := b.ID
cli/internal/bead/property_test.go:178:
cli/internal/bead/property_test.go:179:	validStatuses := allLifecycleStatusesForTests()
cli/internal/bead/property_test.go:180:
cli/internal/bead/property_test.go:181:	for step := 0; step < 200; step++ {
cli/internal/bead/property_test.go:182:		// Read current status before deciding the operation.
cli/internal/bead/property_test.go:183:		current, err := s.Get(testCtx(), id)
cli/internal/bead/property_test.go:184:		require.NoError(t, err, "step %d: Get must succeed", step)
cli/internal/bead/property_test.go:185:
cli/internal/bead/property_test.go:186:		op := rng.Intn(4)
cli/internal/bead/property_test.go:187:		switch op {
cli/internal/bead/property_test.go:188:		case 0: // Claim: only succeeds from StatusOpen.
cli/internal/bead/property_test.go:189:			claimErr := s.Claim(id, "agent")
cli/internal/bead/property_test.go:190:			if current.Status != StatusOpen {
cli/internal/bead/property_test.go:191:				assert.Error(t, claimErr,
cli/internal/bead/property_test.go:192:					"step %d: Claim from %s must error", step, current.Status)
cli/internal/bead/property_test.go:193:			}
cli/internal/bead/property_test.go:194:			// From StatusOpen, claim may succeed or race — don't assert on success.
cli/internal/bead/property_test.go:195:
cli/internal/bead/property_test.go:196:		case 1: // Unclaim: always succeeds (no-op if not in_progress).
cli/internal/bead/property_test.go:197:			assert.NoError(t, s.Unclaim(id), "step %d: Unclaim must never error", step)
cli/internal/bead/property_test.go:198:
cli/internal/bead/property_test.go:199:		case 2: // Close: always succeeds (idempotent if already closed).
cli/internal/bead/property_test.go:200:			assert.NoError(t, s.Close(testCtx(), id), "step %d: Close must never error", step)
cli/internal/bead/property_test.go:201:
cli/internal/bead/property_test.go:202:		case 3: // Reopen through the lifecycle API: always succeeds for this state set.
cli/internal/bead/property_test.go:203:			assert.NoError(t, s.Reopen(id, "", ""),
cli/internal/bead/property_test.go:204:				"step %d: reopen must never error", step)
cli/internal/bead/property_test.go:205:		}
cli/internal/bead/property_test.go:206:
cli/internal/bead/property_test.go:207:		// After every operation the bead must have a valid status.
cli/internal/bead/property_test.go:208:		got, getErr := s.Get(testCtx(), id)
cli/internal/bead/property_test.go:209:		require.NoError(t, getErr, "step %d: Get must succeed after op", step)
cli/internal/bead/property_test.go:210:		assert.Contains(t, validStatuses, got.Status,
cli/internal/bead/property_test.go:211:			"step %d: bead must have valid status after op %d, was %q", step, op, got.Status)
cli/internal/bead/property_test.go:212:	}
cli/internal/bead/property_test.go:213:}
