cli/internal/bead/property_test.go:265:// TestProperty_DepCycleDetection verifies that the dependency graph never
cli/internal/bead/property_test.go:266:// acquires a cycle, regardless of the add order.
cli/internal/bead/property_test.go:267:func TestProperty_DepCycleDetection(t *testing.T) {
cli/internal/bead/property_test.go:268:	t.Parallel()
cli/internal/bead/property_test.go:269:	s := newTestStore(t)
cli/internal/bead/property_test.go:270:
cli/internal/bead/property_test.go:271:	// Create a chain: a -> b -> c -> d
cli/internal/bead/property_test.go:272:	var ids []string
cli/internal/bead/property_test.go:273:	for i := 0; i < 5; i++ {
cli/internal/bead/property_test.go:274:		b := &Bead{Title: fmt.Sprintf("dep-chain-%d", i)}
cli/internal/bead/property_test.go:275:		require.NoError(t, s.Create(testCtx(), b))
cli/internal/bead/property_test.go:276:		ids = append(ids, b.ID)
cli/internal/bead/property_test.go:277:	}
cli/internal/bead/property_test.go:278:
cli/internal/bead/property_test.go:279:	// Build a valid chain: ids[1] depends on ids[0], ids[2] on ids[1], etc.
cli/internal/bead/property_test.go:280:	for i := 1; i < len(ids); i++ {
cli/internal/bead/property_test.go:281:		require.NoError(t, s.DepAdd(ids[i], ids[i-1]), "dep %d->%d must succeed", i, i-1)
cli/internal/bead/property_test.go:282:	}
cli/internal/bead/property_test.go:283:
cli/internal/bead/property_test.go:284:	// Attempt to create a cycle: ids[0] depends on ids[len-1].
cli/internal/bead/property_test.go:285:	err := s.DepAdd(ids[0], ids[len(ids)-1])
cli/internal/bead/property_test.go:286:	assert.Error(t, err, "creating a dependency cycle must be rejected")
cli/internal/bead/property_test.go:287:
cli/internal/bead/property_test.go:288:	// Self-dependency must also be rejected.
cli/internal/bead/property_test.go:289:	err = s.DepAdd(ids[0], ids[0])
cli/internal/bead/property_test.go:290:	assert.Error(t, err, "self-dependency must be rejected")
cli/internal/bead/property_test.go:291:
cli/internal/bead/property_test.go:292:	// Verify the valid chain is intact.
cli/internal/bead/property_test.go:293:	b, err := s.Get(testCtx(), ids[len(ids)-1])
cli/internal/bead/property_test.go:294:	require.NoError(t, err)
cli/internal/bead/property_test.go:295:	assert.True(t, b.HasDep(ids[len(ids)-2]), "dep chain must be preserved after cycle rejection")
cli/internal/bead/property_test.go:296:}
