cli/internal/bead/property_test.go:341:// TestProperty_ReadyAndBlockedInvariants verifies that Ready() and Blocked()
cli/internal/bead/property_test.go:342:// are consistent: Ready beads have all deps closed, Blocked beads have at
cli/internal/bead/property_test.go:343:// least one open/in_progress dep. A bead cannot appear in both lists.
cli/internal/bead/property_test.go:344:func TestProperty_ReadyAndBlockedInvariants(t *testing.T) {
cli/internal/bead/property_test.go:345:	t.Parallel()
cli/internal/bead/property_test.go:346:	s := newTestStore(t)
cli/internal/bead/property_test.go:347:
cli/internal/bead/property_test.go:348:	// Create a dependency graph:
cli/internal/bead/property_test.go:349:	//   prereq (open)
cli/internal/bead/property_test.go:350:	//   dependentA depends on prereq
cli/internal/bead/property_test.go:351:	//   dependentB has no deps
cli/internal/bead/property_test.go:352:	//   closed-one (will be closed)
cli/internal/bead/property_test.go:353:	prereq := &Bead{Title: "prereq"}
cli/internal/bead/property_test.go:354:	depA := &Bead{Title: "dependentA"}
cli/internal/bead/property_test.go:355:	depB := &Bead{Title: "independentB"}
cli/internal/bead/property_test.go:356:	closedOne := &Bead{Title: "closed-one"}
cli/internal/bead/property_test.go:357:
cli/internal/bead/property_test.go:358:	require.NoError(t, s.Create(testCtx(), prereq))
cli/internal/bead/property_test.go:359:	require.NoError(t, s.Create(testCtx(), depA))
cli/internal/bead/property_test.go:360:	require.NoError(t, s.Create(testCtx(), depB))
cli/internal/bead/property_test.go:361:	require.NoError(t, s.Create(testCtx(), closedOne))
cli/internal/bead/property_test.go:362:	require.NoError(t, s.Close(testCtx(), closedOne.ID))
cli/internal/bead/property_test.go:363:
cli/internal/bead/property_test.go:364:	require.NoError(t, s.DepAdd(depA.ID, prereq.ID))
cli/internal/bead/property_test.go:365:
cli/internal/bead/property_test.go:366:	// State: prereq=open(no deps), depA=open(dep on prereq open), depB=open(no deps), closedOne=closed
cli/internal/bead/property_test.go:367:	// Expected: Ready = [prereq, depB], Blocked = [depA]
cli/internal/bead/property_test.go:368:
cli/internal/bead/property_test.go:369:	ready, err := s.Ready()
cli/internal/bead/property_test.go:370:	require.NoError(t, err)
cli/internal/bead/property_test.go:371:	blocked, err := s.Blocked()
cli/internal/bead/property_test.go:372:	require.NoError(t, err)
cli/internal/bead/property_test.go:373:
cli/internal/bead/property_test.go:374:	readyIDs := make(map[string]bool)
cli/internal/bead/property_test.go:375:	for _, b := range ready {
cli/internal/bead/property_test.go:376:		readyIDs[b.ID] = true
cli/internal/bead/property_test.go:377:		assert.Equal(t, StatusOpen, b.Status, "ready bead %s must be open", b.ID)
cli/internal/bead/property_test.go:378:	}
cli/internal/bead/property_test.go:379:	blockedIDs := make(map[string]bool)
cli/internal/bead/property_test.go:380:	for _, b := range blocked {
cli/internal/bead/property_test.go:381:		blockedIDs[b.ID] = true
cli/internal/bead/property_test.go:382:		assert.Equal(t, StatusOpen, b.Status, "blocked bead %s must be open", b.ID)
cli/internal/bead/property_test.go:383:	}
cli/internal/bead/property_test.go:384:
cli/internal/bead/property_test.go:385:	// No overlap between ready and blocked.
cli/internal/bead/property_test.go:386:	for id := range readyIDs {
cli/internal/bead/property_test.go:387:		assert.False(t, blockedIDs[id], "bead %s appears in both ready and blocked", id)
cli/internal/bead/property_test.go:388:	}
cli/internal/bead/property_test.go:389:
cli/internal/bead/property_test.go:390:	// Closed bead must not appear in either.
cli/internal/bead/property_test.go:391:	assert.False(t, readyIDs[closedOne.ID], "closed bead must not be in ready")
cli/internal/bead/property_test.go:392:	assert.False(t, blockedIDs[closedOne.ID], "closed bead must not be in blocked")
cli/internal/bead/property_test.go:393:
cli/internal/bead/property_test.go:394:	// depA (blocked by open prereq) must not be in ready.
cli/internal/bead/property_test.go:395:	assert.False(t, readyIDs[depA.ID], "depA must not be ready while prereq is open")
cli/internal/bead/property_test.go:396:	assert.True(t, blockedIDs[depA.ID], "depA must be blocked while prereq is open")
cli/internal/bead/property_test.go:397:
