cli/internal/bead/property_test.go:558:			ops = append(ops,
cli/internal/bead/property_test.go:559:				op{name: "update-status", fn: func() {
cli/internal/bead/property_test.go:560:					next := validStatuses[rng.Intn(len(validStatuses))]
cli/internal/bead/property_test.go:561:					_ = s.SetLifecycleStatus(id, next, lifecycleTransitionOptionsForTests(next))
cli/internal/bead/property_test.go:562:				}},
cli/internal/bead/property_test.go:563:				op{name: "claim", fn: func() { _ = s.Claim(id, "agent") }},
