cli/internal/bead/property_test.go:568:				}},
cli/internal/bead/property_test.go:569:				op{name: "get", fn: func() { _, _ = s.Get(testCtx(), id) }},
cli/internal/bead/property_test.go:570:			)
cli/internal/bead/property_test.go:571:		}
