cli/internal/bead/bench_test.go:58:			IssueType: DefaultType,
cli/internal/bead/bench_test.go:59:			CreatedAt: ts,
cli/internal/bead/bench_test.go:60:			UpdatedAt: ts,
cli/internal/bead/bench_test.go:61:		}
