cli/internal/bead/bench_test.go:67:			}
cli/internal/bead/bench_test.go:68:			switch i % 3 {
cli/internal/bead/bench_test.go:69:			case 1:
cli/internal/bead/bench_test.go:70:				// Dep on a recent closed bead -> ready.
