cli/internal/bead/bench_test.go:72:				b.Dependencies = []Dependency{{
cli/internal/bead/bench_test.go:73:					IssueID:     b.ID,
cli/internal/bead/bench_test.go:74:					DependsOnID: fmt.Sprintf("bench-%04d", target),
