cli/internal/bead/axon_backend_test.go:483:
cli/internal/bead/axon_backend_test.go:484:	b := &Bead{Title: "race"}
cli/internal/bead/axon_backend_test.go:485:	require.NoError(t, s.Create(testCtx(), b))
cli/internal/bead/axon_backend_test.go:486:
cli/internal/bead/axon_backend_test.go:487:	const goroutines = 8
cli/internal/bead/axon_backend_test.go:488:	var (
cli/internal/bead/axon_backend_test.go:489:		wg       sync.WaitGroup
cli/internal/bead/axon_backend_test.go:490:		successN int
cli/internal/bead/axon_backend_test.go:491:		mu       sync.Mutex
cli/internal/bead/axon_backend_test.go:492:	)
cli/internal/bead/axon_backend_test.go:493:	for i := 0; i < goroutines; i++ {
cli/internal/bead/axon_backend_test.go:494:		wg.Add(1)
cli/internal/bead/axon_backend_test.go:495:		go func(i int) {
cli/internal/bead/axon_backend_test.go:496:			defer wg.Done()
